mapper.select:
SELECT 
FROM mq_message_idempotency
WHERE message_id = #{messageId}
  AND consumer_group = #{consumerGroup}
  AND deleted = 0

SELECT 
FROM mq_message_idempotency
WHERE business_key = #{businessKey}
  AND consumer_group = #{consumerGroup}
  AND deleted = 0

mapper.delete:
DELETE FROM mq_message_idempotency
WHERE create_time < #{expireTime}
  AND status IN (1, 2)

mapper.update:
UPDATE mq_message_idempotency
SET retry_count = retry_count + 1,
    update_time = NOW()
WHERE message_id = #{messageId}
  AND consumer_group = #{consumerGroup}
  AND deleted = 0
